SELECT * FROM haosen_project..hr_monitoring_data
AND batch_id = #{condition.batchId}
AND key_id = #{condition.keyId}
AND address LIKE '%' + #{condition.address} + '%'
AND product_name LIKE '%' + #{condition.productName} + '%'
AND name LIKE '%' + #{condition.name} + '%'
AND business_license_name LIKE '%' + #{condition.businessLicenseName} + '%'
AND province = #{condition.province}
AND created_time >= #{condition.createTime} + ' 00:00:00' AND created_time <= #{condition.createTime} + ' 23:59:59'
ORDER BY create_time DESC

mapper.update:
-- 步骤 1: 更新临时表的标准化省份 UPDATE haosen_project..hr_monitoring_data_tmp SET standardized_province = a.省 FROM test..行政区划表0928_民政部 a WHERE CHARINDEX(hr_monitoring_data_tmp.province, a.省) > 0 AND batch_id = #{batchId};
-- 步骤 2: 从比对关系表补充 key_id, name, address (优先匹配省份 + 营业执照) UPDATE haosen_project..hr_monitoring_data_tmp SET key_id = a.key_id, name = a.name, address = a.address FROM haosen_project..hr_org_relation a WHERE hr_monitoring_data_tmp.standardized_province = a.province AND hr_monitoring_data_tmp.business_license_name = a.business_license_name AND hr_monitoring_data_tmp.key_id IS NULL AND hr_monitoring_data_tmp.batch_id = #{batchId};
-- 步骤 3: 从比对关系表补充 key_id, name, address (仅匹配营业执照) UPDATE haosen_project..hr_monitoring_data_tmp SET key_id = a.key_id, name = a.name, address = a.address FROM haosen_project..hr_org_relation a WHERE hr_monitoring_data_tmp.business_license_name = a.business_license_name AND hr_monitoring_data_tmp.key_id IS NULL AND hr_monitoring_data_tmp.batch_id = #{batchId};
-- 步骤 4: 将数据从临时表转移到正式表 INSERT INTO haosen_project..hr_monitoring_data ( batch_id, serial_no, monitoring_year, id, product_name, platform, generic_name, url, specification, online_store_price, box_quantity, unit_price_per_box, store_name, business_license_name, province, city, sales_volume, category, created_time, crawled_time, repeated_count, shipping_origin, key_id, name, address, standardized_province, short_name, remarks, create_time, update_time ) SELECT batch_id, serial_no, monitoring_year, id, product_name, platform, generic_name, url, specification, online_store_price, box_quantity, unit_price_per_box, store_name, business_license_name, province, city, sales_volume, category, created_time, crawled_time, repeated_count, shipping_origin, key_id, name, address, standardized_province, short_name, remarks, GETDATE(), GETDATE() FROM ( -- 第一部分：key_id 不为空的数据直接插入 SELECT batch_id, serial_no, monitoring_year, id, product_name, platform, generic_name, url, specification, online_store_price, box_quantity, unit_price_per_box, store_name, business_license_name, province, city, sales_volume, category, created_time, crawled_time, repeated_count, shipping_origin, key_id, name, address, standardized_province, short_name, remarks FROM haosen_project..hr_monitoring_data_tmp WHERE key_id IS NOT NULL AND batch_id = #{batchId} UNION ALL -- 第二部分：key_id 为空的数据，通过标准名称/历史名称匹配后插入 SELECT a.batch_id, a.serial_no, a.monitoring_year, a.id, a.product_name, a.platform, a.generic_name, a.url, a.specification, a.online_store_price, a.box_quantity, a.unit_price_per_box, a.store_name, a.business_license_name, a.province, a.city, a.sales_volume, a.category, a.created_time, a.crawled_time, a.repeated_count, a.shipping_origin, c.key_id, c.name, c.address, a.standardized_province, a.short_name, a.remarks FROM ( SELECT batch_id, serial_no, monitoring_year, id, product_name, platform, generic_name, url, specification, online_store_price, box_quantity, unit_price_per_box, store_name, business_license_name, province, city, sales_volume, category, created_time, crawled_time, repeated_count, shipping_origin, standardized_province, short_name, remarks FROM haosen_project..hr_monitoring_data_tmp WHERE key_id IS NULL AND batch_id = #{batchId} ) a LEFT JOIN ( SELECT * FROM test..医院_标准名称 UNION ALL SELECT * FROM test..医院_历史名称 UNION ALL SELECT * FROM test..药店_标准名称 UNION ALL SELECT * FROM test..药店_历史名称 ) b ON a.business_license_name = REPLACE(REPLACE(REPLACE(b.name, '（', '('), '）', ')'), ' ', '') AND a.standardized_province = b.province LEFT JOIN ( SELECT keyid AS key_id, name AS name, address AS address FROM HospitalInfo..hospital UNION ALL SELECT key_id AS key_id, name AS name, address AS address FROM HospitalInfo..company ) c ON b.keyid = c.key_id ) AS combined_data;
-- 步骤 5: 同步比对关系数据到 hr_org_relation 表 INSERT INTO haosen_project..hr_org_relation (business_license_name, province, key_id, name, address, add_time, update_time) SELECT t.business_license_name, t.standardized_province, t.key_id, t.name, t.address, GETDATE(), GETDATE() FROM ( SELECT business_license_name, standardized_province, key_id, name, address, ROW_NUMBER() OVER (PARTITION BY business_license_name ORDER BY create_time DESC) AS rn FROM haosen_project..hr_monitoring_data WHERE batch_id = #{batchId} AND business_license_name <> '' ) t WHERE t.rn = 1 AND NOT EXISTS ( SELECT 1 FROM haosen_project..hr_org_relation h WHERE h.business_license_name = t.business_license_name ) AND t.key_id <> '';
-- 步骤 6: 更新批次状态为已处理 (status=1) UPDATE haosen_project..hr_batch SET status = 1, update_time = GETDATE(),message = '处理完成' WHERE batch_id = #{batchId};
